    /// @dev Contract owner.
    address public owner;
    /// @dev Amount in wei that is required to be paid when calling `paimaSubmitGameInput`.
    uint256 public fee; // in wei

    /// @dev Sets the contract owner to `_owner` and payment fee to `_fee`.
